(function () {
  'use strict';

  // Logo PNG real (GRUPODBLOGO.png convertida para Base64)
  var LOGO_B64 = '';

  class DBLogin extends HTMLElement {
    constructor() {
      super();
      this.attachShadow({ mode: 'open' });
    }

    connectedCallback() {
      this.render();
      this.bindEvents();
    }

    render() {
      this.shadowRoot.innerHTML = `
        <style>
          :host {
            display: flex;
            position: fixed;
            inset: 0;
            align-items: center;
            justify-content: center;
            background: var(--navy, #003761);
            z-index: 999;
          }

          /* Fundo com gradiente sutil igual ao print (azul escuro) */
          .login-bg {
            position: absolute;
            inset: 0;
            background:
              radial-gradient(ellipse at 30% 20%, rgba(15,155,148,0.12) 0%, transparent 55%),
              radial-gradient(ellipse at 80% 80%, rgba(0,74,128,0.35) 0%, transparent 55%),
              #002e55;
          }

          .login-box {
            position: relative;
            z-index: 1;
            width: min(480px, 92%);
            background: #ffffff;
            border-radius: 20px;
            box-shadow:
              0 32px 80px rgba(0, 18, 40, 0.45),
              0 0 0 1px rgba(255,255,255,0.06);
            padding: 40px 40px 36px;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0;
          }

          /* Logo no topo, centralizada */
          .login-logo-wrap {
            display: flex;
            align-items: center;
            justify-content: center;
            margin-bottom: 20px;
          }

          .login-logo-img {
            height: 48px;
            width: auto;
            object-fit: contain;
            display: block;
          }

          /* Fallback caso logo não carregue */
          .login-logo-text {
            font-size: 28px;
            font-weight: 800;
            color: var(--navy, #003761);
            letter-spacing: -0.5px;
          }

          .login-title {
            font-size: 22px;
            font-weight: 700;
            color: var(--accent, #0F9B94);
            text-align: center;
            margin-bottom: 6px;
            letter-spacing: -0.2px;
          }

          .login-sub {
            font-size: 13px;
            color: #8a96a8;
            text-align: center;
            margin-bottom: 28px;
            line-height: 1.4;
          }

          .login-fields {
            width: 100%;
            display: flex;
            flex-direction: column;
            gap: 16px;
          }

          .login-field {
            display: flex;
            flex-direction: column;
            gap: 6px;
            width: 100%;
          }

          .login-label {
            font-size: 11px;
            font-weight: 700;
            color: #8a96a8;
            text-transform: uppercase;
            letter-spacing: 0.12em;
          }

          .login-input {
            width: 100%;
            border: 1.5px solid #d4dbe6;
            border-radius: 10px;
            padding: 13px 15px;
            font-size: 14px;
            color: #1a2433;
            outline: none;
            transition: border-color .18s, box-shadow .18s;
            background: #f8fafc;
            font-family: inherit;
            box-sizing: border-box;
          }

          .login-input:focus {
            border-color: var(--accent, #0F9B94);
            background: #fff;
            box-shadow: 0 0 0 3px rgba(15,155,148,0.10);
          }

          .login-input::placeholder {
            color: #b0bac8;
          }

          .login-btn {
            width: 100%;
            padding: 14px 16px;
            background: var(--accent, #0F9B94);
            border: none;
            border-radius: 10px;
            color: white;
            font-size: 15px;
            font-weight: 700;
            cursor: pointer;
            transition: background .18s, transform .12s, box-shadow .18s;
            margin-top: 8px;
            letter-spacing: 0.02em;
            font-family: inherit;
            box-shadow: 0 4px 14px rgba(15,155,148,0.30);
          }

          .login-btn:hover {
            background: #0a7a74;
            transform: translateY(-1px);
            box-shadow: 0 6px 20px rgba(15,155,148,0.38);
          }

          .login-btn:active {
            transform: translateY(0);
          }

          .login-error {
            color: #d63031;
            font-size: 12px;
            text-align: center;
            min-height: 16px;
            margin-top: 6px;
            font-weight: 500;
          }
        </style>

        <div class="login-bg"></div>

        <div class="login-box">
          <!-- Logo real do Grupo DB -->
          <div class="login-logo-wrap">
            <img
              class="login-logo-img"
              src="data:image/png;base64,"
              alt="Grupo DB"
              onerror="this.style.display='none';this.nextElementSibling.style.display='block'"
            >
            <span class="login-logo-text" style="display:none">GRUPO DB</span>
          </div>

          <div class="login-title">DB Lab Manager</div>
          <div class="login-sub">Faça login para continuar</div>

          <div class="login-fields">
            <div class="login-field">
              <label class="login-label" for="login-user">Login</label>
              <input
                type="text"
                class="login-input"
                id="login-user"
                placeholder="Usuário"
                autocomplete="username"
              >
            </div>

            <div class="login-field">
              <label class="login-label" for="login-pass">Senha</label>
              <input
                type="password"
                class="login-input"
                id="login-pass"
                placeholder="••••••••"
                autocomplete="current-password"
              >
            </div>

            <button class="login-btn" id="login-btn" type="button">Entrar</button>
            <div class="login-error" id="login-error"></div>
          </div>
        </div>
      `;
    }

    bindEvents() {
      this.shadowRoot.addEventListener('click', (e) => {
        if (e.target.id === 'login-btn') {
          this.dispatchEvent(new CustomEvent('db-login-submit', { bubbles: true, composed: true }));
        }
      });

      this.shadowRoot.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') {
          e.preventDefault();
          this.dispatchEvent(new CustomEvent('db-login-submit', { bubbles: true, composed: true }));
        }
      });
    }

    getCredentials() {
      return {
        login:    this.shadowRoot.getElementById('login-user').value,
        password: this.shadowRoot.getElementById('login-pass').value,
      };
    }

    setError(msg) {
      this.shadowRoot.getElementById('login-error').textContent = msg || '';
    }

    reset() {
      this.shadowRoot.getElementById('login-user').value = '';
      this.shadowRoot.getElementById('login-pass').value = '';
      this.setError('');
    }

    focus() {
      this.shadowRoot.getElementById('login-user').focus();
    }
  }

  customElements.define('db-login', DBLogin);
  window.DBLogin = DBLogin;
})();
